func TestRun_DSCSection_RemovedComponentIgnored(t *testing.T) {
	sch := scheme.Scheme
	_ = corev1.AddToScheme(sch)
	_ = appsv1.AddToScheme(sch)
	// DSC with Kueue Removed and KueueReady=False: we should not report unhealthy for Kueue.
	// Dashboard Managed and DashboardReady=False: we should report unhealthy.
	dsc := &unstructured.Unstructured{}
	dsc.SetGroupVersionKind(gvk.DataScienceCluster)
	dsc.SetName("default-dsc")
	dsc.Object["spec"] = map[string]interface{}{
		"components": map[string]interface{}{
			"dashboard": map[string]interface{}{"managementState": "Managed"},
			"kueue":     map[string]interface{}{"managementState": "Removed"},
		},
	}
	dsc.Object["status"] = map[string]interface{}{
		"conditions": []interface{}{
			map[string]interface{}{"type": "DashboardReady", "status": "False", "message": "not ready"},
			map[string]interface{}{"type": "KueueReady", "status": "False", "message": "removed"},
		},
	}
	cl := fake.NewClientBuilder().WithScheme(sch).WithObjects(dsc).Build()
	cfg := Config{
		Client:       cl,
		DSCI:         types.NamespacedName{},
		DSC:          types.NamespacedName{},
		OnlySections: []string{SectionDSC},
	}
	report, err := Run(context.Background(), cfg)
	if err != nil {
		t.Fatalf("Run: %v", err)
	}
	// Should be unhealthy due to DashboardReady=False (Kueue is Removed so we ignore KueueReady).
	if report.DSC.Error == "" {
		t.Error("DSC section should have Error when managed component Dashboard is not ready")
	}
	if !strings.Contains(report.DSC.Error, "DashboardReady=False") {
		t.Errorf("DSC.Error should contain DashboardReady=False; got %q", report.DSC.Error)
	}
	if strings.Contains(report.DSC.Error, "KueueReady") {
		t.Errorf("DSC.Error should not mention KueueReady (component is Removed); got %q", report.DSC.Error)
	}
}

