func TestRun_OperatorSection_DependentOperators(t *testing.T) {
	sch := scheme.Scheme
	_ = corev1.AddToScheme(sch)
	_ = appsv1.AddToScheme(sch)

	one := int32(1)
	mainDeploy := &appsv1.Deployment{
		ObjectMeta: metav1.ObjectMeta{Name: "op-deploy", Namespace: "op-ns"},
		Spec: appsv1.DeploymentSpec{
			Replicas: &one,
			Selector: &metav1.LabelSelector{MatchLabels: map[string]string{"app": "op"}},
		},
		Status: appsv1.DeploymentStatus{Replicas: 1, ReadyReplicas: 1},
	}
	// OpenTelemetry operator namespace; discovery finds any deployment in the namespace
	otelDeploy := &appsv1.Deployment{
		ObjectMeta: metav1.ObjectMeta{Name: "opentelemetry-product", Namespace: "openshift-opentelemetry-operator"},
		Spec: appsv1.DeploymentSpec{
			Replicas: &one,
			Selector: &metav1.LabelSelector{MatchLabels: map[string]string{"app": "opentelemetry"}},
		},
		Status: appsv1.DeploymentStatus{Replicas: 1, ReadyReplicas: 1},
	}
	otelDeployUnhealthy := &appsv1.Deployment{
		ObjectMeta: metav1.ObjectMeta{Name: "opentelemetry-product", Namespace: "openshift-opentelemetry-operator"},
		Spec: appsv1.DeploymentSpec{
			Replicas: &one,
			Selector: &metav1.LabelSelector{MatchLabels: map[string]string{"app": "opentelemetry"}},
		},
		Status: appsv1.DeploymentStatus{Replicas: 1, ReadyReplicas: 0},
	}

	// All known dependent operator names (must match operator.go dependentOperatorNamespaces).
	allDependentNames := []string{"opentelemetry", "tempo", "cluster-observability", "kueue", "jobset", "leader-worker-set", "cert-manager", "kuadrant"}

	tests := []struct {
		name               string
		objs               []client.Object
		wantDeps           int
		wantNames          []string
		wantInstalledCount int
		wantErrContain     []string
	}{
		{
			name:               "no dependents installed - only main operator",
			objs:               []client.Object{mainDeploy},
			wantDeps:           len(allDependentNames),
			wantNames:          allDependentNames,
			wantInstalledCount: 0,
			wantErrContain:     nil,
		},
		{
			name:               "one dependent installed and healthy",
			objs:               []client.Object{mainDeploy, otelDeploy},
			wantDeps:           len(allDependentNames),
			wantNames:          allDependentNames,
			wantInstalledCount: 1,
			wantErrContain:     nil,
		},
		{
			name:               "one dependent installed but unhealthy",
			objs:               []client.Object{mainDeploy, otelDeployUnhealthy},
			wantDeps:           len(allDependentNames),
			wantNames:          allDependentNames,
			wantInstalledCount: 1,
			wantErrContain:     []string{"dependent opentelemetry"},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			cl := fake.NewClientBuilder().WithScheme(sch).WithObjects(tt.objs...).Build()
			cfg := Config{
				Client:       cl,
				Namespaces:   NamespaceConfig{},
				Operator:     OperatorConfig{Namespace: "op-ns", Name: "op-deploy"},
				OnlySections: []string{SectionOperator},
			}
			report, err := Run(context.Background(), cfg)
			if err != nil {
				t.Fatalf("Run: %v", err)
			}
			deps := report.Operator.Data.DependentOperators
			if len(deps) != tt.wantDeps {
				t.Errorf("DependentOperators length = %d, want %d", len(deps), tt.wantDeps)
			}
			names := make(map[string]bool)
			for _, d := range deps {
				names[d.Name] = true
			}
			for _, want := range tt.wantNames {
				if !names[want] {
					t.Errorf("DependentOperators want %q, got %v", want, names)
				}
			}
			installedCount := 0
			for _, d := range deps {
				if d.Installed {
					installedCount++
				}
			}
			if installedCount != tt.wantInstalledCount {
				t.Errorf("DependentOperators installed count = %d, want %d", installedCount, tt.wantInstalledCount)
			}
			for _, sub := range tt.wantErrContain {
				if !strings.Contains(report.Operator.Error, sub) {
					t.Errorf("Operator.Error should contain %q: %q", sub, report.Operator.Error)
				}
			}
		})
	}
}

func TestReport_PrettyPrint(t *testing.T) {
	t.Run("table header and all sections", func(t *testing.T) {
		r := &Report{CollectedAt: time.Now()}
		out := r.PrettyPrint(false)
		if !strings.Contains(out, "SECTION") || !strings.Contains(out, "STATUS") || !strings.Contains(out, "SUMMARY") {
			t.Errorf("PrettyPrint should contain table header; got:\n%s", out)
		}
		for _, name := range []string{"Nodes", "Deployments", "Pods", "Events", "Quotas", "Operator", "DSCI", "DSC"} {
			if !strings.Contains(out, name) {
				t.Errorf("PrettyPrint should contain section %q; got:\n%s", name, out)
			}
		}
	})
	t.Run("FAIL and summary when section has error", func(t *testing.T) {
		r := &Report{
			CollectedAt: time.Now(),
			Operator:    SectionResult[OperatorSection]{Error: "operator deployment not found: deployments.apps \"x\" not found"},
		}
		out := r.PrettyPrint(false)
		if !strings.Contains(out, "FAIL") {
			t.Errorf("PrettyPrint should contain FAIL when section has error; got:\n%s", out)
		}
		if !strings.Contains(out, "operator deployment not found") {
			t.Errorf("PrettyPrint summary should contain error message; got:\n%s", out)
		}
	})
	t.Run("OK and summary when section has data", func(t *testing.T) {
		r := &Report{
			CollectedAt: time.Now(),
			Nodes: SectionResult[NodesSection]{
				Data: NodesSection{Nodes: []NodeInfo{{Name: "node-1"}, {Name: "node-2"}}},
			},
		}
		out := r.PrettyPrint(false)
		if !strings.Contains(out, "OK") {
			t.Errorf("PrettyPrint should contain OK for healthy section; got:\n%s", out)
		}
		if !strings.Contains(out, "2 nodes") {
			t.Errorf("PrettyPrint Nodes summary should be '2 nodes'; got:\n%s", out)
		}
	})
	t.Run("only sections in SectionsRun are shown", func(t *testing.T) {
		r := &Report{
			CollectedAt: time.Now(),
			SectionsRun: []string{SectionNodes, SectionOperator},
			Nodes:       SectionResult[NodesSection]{Data: NodesSection{Nodes: []NodeInfo{{Name: "n1"}}}},
			Operator:    SectionResult[OperatorSection]{Data: OperatorSection{Deployment: &DeploymentInfo{Name: "op", Ready: 1, Replicas: 1}}},
		}
		out := r.PrettyPrint(false)
		if !strings.Contains(out, "Nodes") || !strings.Contains(out, "Operator") {
			t.Errorf("PrettyPrint with SectionsRun should show Nodes and Operator; got:\n%s", out)
		}
		if strings.Contains(out, "Deployments") || strings.Contains(out, "Pods") {
			t.Errorf("PrettyPrint with SectionsRun should not show Deployments or Pods; got:\n%s", out)
		}
	})
}
